const express = require('express');
const session = require('express-session');
const bodyParser = require('body-parser');
const randomstring = require('randomstring');
const twilio = require('twilio');

const app = express();
const client = new twilio('TWILIO_ACCOUNT_SID', 'TWILIO_AUTH_TOKEN');
const PORT = 3000;
const CODE_LENGTH = 6;
let sessions = {};

app.use(session({ secret: 'secret', resave: false, saveUninitialized: true }));
app.use(bodyParser.urlencoded({ extended: false }));

function generateRandomCode() {
  return randomstring.generate({
    length: CODE_LENGTH,
    charset: 'numeric'
  });
}

app.post('/login', (req, res) => {
  const phoneNumber = req.body.phoneNumber;
  const code = generateRandomCode();
  sessions[req.session.id] = { phoneNumber, code };
  client.messages.create({
    body: `Your authentication code is: ${code}`,
    from: 'YOUR_TWILIO_PHONE_NUMBER',
    to: phoneNumber
  });
  res.send('Enter authentication code sent to your phone');
});

app.post('/verify', (req, res) => {
  const sessionID = req.session.id;
  const { code } = req.body;
  if (sessions[sessionID] && sessions[sessionID].code === code) {
    res.send('Authentication successful');
  } else {
    res.send('Invalid authentication code');
  }
});

app.listen(PORT, () => {
  console.log(`Server is running on http://localhost:${PORT}`);
});